// src/components/Navbar.js
import React, { useEffect, useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { onAuthStateChanged } from "firebase/auth";
import { auth } from "../firebase";
import { useAuth } from "../context/AuthContext"; // ✅ use the AuthContext

const Navbar = () => {
  const [user, setUser] = useState(null);
  const { loginWithGoogle, logout } = useAuth(); // ✅ bring in context actions
  const navigate = useNavigate();

  // Monitor authentication state
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, (currentUser) => {
      setUser(currentUser);
    });
    return () => unsubscribe();
  }, []);

  const handleLogin = async () => {
    try {
      await loginWithGoogle();
      navigate("/dashboard");
    } catch (error) {
      console.error("Login failed:", error);
    }
  };

  const handleLogout = async () => {
    try {
      await logout();
      navigate("/");
    } catch (error) {
      console.error("Logout failed:", error);
    }
  };

  return (
    <nav className="w-full bg-gradient-to-r from-gray-900 via-black to-gray-800 text-white shadow-lg sticky top-0 z-50">
      <div className="max-w-7xl mx-auto px-6 py-3 flex justify-between items-center">
        {/* Logo / Brand */}
        <Link
          to="/"
          className="text-2xl font-extrabold tracking-wide text-yellow-400 hover:text-white transition duration-300"
        >
          Godemar’s Empire
        </Link>

        {/* Navigation Links */}
        <div className="hidden md:flex space-x-8 items-center">
          {!user ? (
            <>
              <Link to="/" className="hover:text-yellow-400 transition">Home</Link>
              <Link to="/about" className="hover:text-yellow-400 transition">About</Link>
              <Link to="/purpose" className="hover:text-yellow-400 transition">Purpose</Link>
              <Link to="/careers" className="hover:text-yellow-400 transition">Careers</Link>
              <button
                onClick={handleLogin}
                className="bg-yellow-400 text-black px-4 py-2 rounded-full hover:bg-yellow-500 transition"
              >
                Login
              </button>
              <button
                onClick={handleLogin}
                className="border border-yellow-400 px-4 py-2 rounded-full hover:bg-yellow-400 hover:text-black transition"
              >
                Sign Up
              </button>
            </>
          ) : (
            <>
              <Link to="/dashboard" className="hover:text-yellow-400 transition">Dashboard</Link>
              <Link to="/profile" className="hover:text-yellow-400 transition">Profile</Link>
              <Link to="/careers" className="hover:text-yellow-400 transition">Careers & Job Offers</Link>
              <Link to="/vision" className="hover:text-yellow-400 transition">Vision</Link>
              <Link to="/team" className="hover:text-yellow-400 transition">Team</Link>
              <Link to="/contact" className="hover:text-yellow-400 transition">Contact</Link>
              <Link to="/about" className="hover:text-yellow-400 transition">About</Link>
              <button
                onClick={handleLogout}
                className="bg-yellow-400 text-black px-4 py-2 rounded-full hover:bg-yellow-500 transition"
              >
                Logout
              </button>
            </>
          )}
        </div>

        {/* Mobile Menu (toggle) */}
        <div className="md:hidden flex items-center">
          <button
            className="text-yellow-400 focus:outline-none"
            onClick={() =>
              document.getElementById("mobile-menu").classList.toggle("hidden")
            }
          >
            ☰
          </button>
        </div>
      </div>

      {/* Mobile Menu Links */}
      <div id="mobile-menu" className="hidden md:hidden bg-black px-6 py-4 space-y-3">
        {!user ? (
          <>
            <Link to="/" className="block hover:text-yellow-400 transition">Home</Link>
            <Link to="/about" className="block hover:text-yellow-400 transition">About</Link>
            <Link to="/purpose" className="block hover:text-yellow-400 transition">Purpose</Link>
            <Link to="/careers" className="block hover:text-yellow-400 transition">Careers</Link>
            <button
              onClick={handleLogin}
              className="w-full bg-yellow-400 text-black py-2 rounded-full hover:bg-yellow-500 transition"
            >
              Login / Sign Up
            </button>
          </>
        ) : (
          <>
            <Link to="/dashboard" className="block hover:text-yellow-400 transition">Dashboard</Link>
            <Link to="/profile" className="block hover:text-yellow-400 transition">Profile</Link>
            <Link to="/careers" className="block hover:text-yellow-400 transition">Careers & Job Offers</Link>
            <Link to="/vision" className="block hover:text-yellow-400 transition">Vision</Link>
            <Link to="/team" className="block hover:text-yellow-400 transition">Team</Link>
            <Link to="/contact" className="block hover:text-yellow-400 transition">Contact</Link>
            <Link to="/about" className="block hover:text-yellow-400 transition">About</Link>
            <button
              onClick={handleLogout}
              className="w-full bg-yellow-400 text-black py-2 rounded-full hover:bg-yellow-500 transition"
            >
              Logout
            </button>
          </>
        )}
      </div>
    </nav>
  );
};

export default Navbar;
